fun solve(nums: Array<Long>): Long {
    val onesIndices = mutableListOf<Int>()
    val twosIndices = mutableListOf<Int>()

    for (k in nums.indices) {
        val value = nums[k]
        if (value == 1L) {
            onesIndices.add(k)
        } else if (value == 2L) {
            twosIndices.add(k)
        }
    }

    if (onesIndices.isEmpty() || twosIndices.isEmpty()) {
        return -1L
    }

    var minDiff = Long.MAX_VALUE

    var p1 = 0
    var p2 = 0

    val n1 = onesIndices.size
    val n2 = twosIndices.size

    while (p1 < n1 && p2 < n2) {
        val i = onesIndices[p1]
        val j = twosIndices[p2]

        // Calculate absolute difference: |i - j|
        val diff = kotlin.math.abs(i.toLong() - j.toLong())

        if (diff < minDiff) {
            minDiff = diff
        }

        // Two-pointer optimization:
        // Move the pointer corresponding to the smaller index.
        // If i < j, we need a larger i to potentially decrease the gap (j - i).
        if (i < j) {
            p1++
        } 
        // If i > j, we need a larger j to potentially decrease the gap (i - j).
        else { 
            p2++
        }
    }

    return minDiff
}

